#include<bits/stdc++.h>
using namespace std;
const long long inf=10000000000;
vector<pair<long long,long long> >edge[100005];
set<pair<long long,long long> >q;//存的是最短路和去的点 
int n,m,s;
int dis[100005];//从s到i的最短路
int main()
{

	cin>>n>>m>>s;
	for(long long i=1;i<=n;i++)if(s!=i)dis[i]=inf;
	for(int i=0;i<m;i++){
		int u,v,w;
		cin>>u>>v>>w;
		edge[u].push_back({v,w});
	}
	q.insert({dis[s],s});
	while(q.size()){
		int x=q.begin()->second;
		q.erase(q.begin());
		for(auto i:edge[x]){
			int to=i.first,w=i.second;
			if(dis[x]+w<dis[to]){
				q.erase({dis[to],to});
				dis[to]=dis[x]+w;
				q.insert({dis[to],to});
			}
		}
	}
	for(int i=1;i<=n;i++){
		cout<<dis[i]<<" ";
	}
}
